class Solution:
    def updateMatrix(self, mat):
        rows = len(mat)
        cols = len(mat[0])
        INF = float('inf')
        dist = [[0 if mat[r][c] == 0 else INF for c in range(cols)] for r in range(rows)]
        changed = True
        while changed:
            changed = False
            for r in range(rows):
                for c in range(cols):
                    for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < rows and 0 <= nc < cols and dist[nr][nc] + 1 < dist[r][c]:
                            dist[r][c] = dist[nr][nc] + 1
                            changed = True
        return dist

